using System.Net;using System.Net.Http.Json;using System.Text.Json;using DBH.UnitTest.Shared;namespace DBH.UnitTest.E2E;/// <summary>/// EHR Version History Flow: Test version tracking across multiple updates/// Flow: Create EHR ÔĺĆ Get Versions (v1) ÔĺĆ Update EHR ÔĺĆ Get Versions (v2) ÔĺĆ ///       Get Specific Version ÔĺĆ Update Again ÔĺĆ Get All Versions ÔĺĆ Verify History/// Expected: Version history correctly tracks all changes/// </summary>public class EhrVersionHistoryTests : ApiTestBase{    protected override IReadOnlyCollection<string> RequiredServices => new[]    {        "AuthService",        "EhrService"    };    [SkippableFact]    public async Task EhrVersionHistory_MultipleUpdates_ShouldTrackVersions()    {        await AuthenticateAsDoctorAsync(EhrClient);        // =====================================================================        // STEP 1: CREATE INITIAL EHR RECORD        // =====================================================================        var createRequest = new         {             patientId = TestSeedData.PatientUserId,             orgId = TestSeedData.HospitalAOrgId,             encounterId = Guid.NewGuid(),             data = new             {                 doctorId = TestSeedData.DoctorUserId,                 diagnosis = "Version test - Initial",                 treatment = "Initial treatment",                 notes = "First version"             }         };        var createResponse = await PostAsJsonWithRetryAsync(EhrClient, ApiEndpoints.Ehr.CreateRecord, createRequest);        var createJson = await ReadJsonResponseAsync(createResponse);                if (!createJson.TryGetProperty("ehrId", out var ehrIdElement))            return;        var ehrId = Guid.Parse(ehrIdElement.GetString()!);        // =====================================================================        // STEP 2: GET INITIAL VERSIONS        // =====================================================================        var versionResponse1 = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.Versions(ehrId));        Assert.Equal(HttpStatusCode.OK, versionResponse1.StatusCode);                var versionJson1 = await ReadJsonResponseAsync(versionResponse1);        Assert.True(versionJson1.ValueKind == JsonValueKind.Array);        var initialVersionCount = versionJson1.GetArrayLength();        Assert.True(initialVersionCount >= 1, "Should have at least 1 version after creation");        // =====================================================================        // STEP 3: UPDATE RECORD - CREATE VERSION 2        // =====================================================================        var updateRequest1 = new         {             diagnosis = "Version test - First Update",             treatment = "Updated treatment",             notes = "Second version"         };        var updateResponse1 = await PutAsJsonWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.UpdateRecord(ehrId),             updateRequest1);                Assert.True(            updateResponse1.StatusCode == HttpStatusCode.OK ||             updateResponse1.StatusCode == HttpStatusCode.NoContent);        // =====================================================================        // STEP 4: GET VERSIONS AFTER FIRST UPDATE        // =====================================================================        var versionResponse2 = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.Versions(ehrId));        Assert.Equal(HttpStatusCode.OK, versionResponse2.StatusCode);                var versionJson2 = await ReadJsonResponseAsync(versionResponse2);        var versionCountAfterUpdate1 = versionJson2.GetArrayLength();        Assert.True(versionCountAfterUpdate1 >= initialVersionCount,             "Version count should increase or stay same after update");        // =====================================================================        // STEP 5: GET SPECIFIC VERSION (if available)        // =====================================================================        if (versionJson2.GetArrayLength() > 0)        {            if (versionJson2[0].TryGetProperty("versionId", out var versionIdElement))            {                var versionId = Guid.Parse(versionIdElement.GetString()!);                                var specificVersionResponse = await GetWithRetryAsync(                    EhrClient,                     ApiEndpoints.Ehr.VersionById(ehrId, versionId));                Assert.True(                    specificVersionResponse.StatusCode == HttpStatusCode.OK ||                     specificVersionResponse.StatusCode == HttpStatusCode.NotFound);            }        }        // =====================================================================        // STEP 6: UPDATE RECORD AGAIN - CREATE VERSION 3        // =====================================================================        var updateRequest2 = new         {             diagnosis = "Version test - Second Update",             treatment = "Updated treatment again",             notes = "Third version"         };        var updateResponse2 = await PutAsJsonWithRetryAsync(            EhrClient,             ApiEndpoints.Ehr.UpdateRecord(ehrId),             updateRequest2);                Assert.True(            updateResponse2.StatusCode == HttpStatusCode.OK ||             updateResponse2.StatusCode == HttpStatusCode.NoContent);        // =====================================================================        // STEP 7: GET FINAL VERSION LIST        // =====================================================================        var versionResponseFinal = await GetWithRetryAsync(EhrClient, ApiEndpoints.Ehr.Versions(ehrId));        Assert.Equal(HttpStatusCode.OK, versionResponseFinal.StatusCode);                var versionJsonFinal = await ReadJsonResponseAsync(versionResponseFinal);        Assert.True(versionJsonFinal.ValueKind == JsonValueKind.Array);        var finalVersionCount = versionJsonFinal.GetArrayLength();        // Version history should show progression        Assert.True(finalVersionCount >= initialVersionCount,             "Final version count should be >= initial version count");        // Test completed successfully        Assert.True(true, "Version history tracking succeeded");    }}